// Schema definition with strict typing
const typeDefs = gql`
  type Invoice {
    id: ID!
    invoiceNumber: String!
    amount: Float!
    currency: String!
    status: InvoiceStatus!
    issuedDate: String!
    dueDate: String!
    lineItems: [LineItem!]!
    customerName: String!
    customerEmail: String!
  }

  type LineItem {
    description: String!
    quantity: Int!
    unitPrice: Float!
    total: Float!
  }

  enum InvoiceStatus {
    DRAFT
    SENT
    PAID
    OVERDUE
    CANCELLED
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

// Input validation utilities
const INVOICE_ID_PATTERN = /^[a-zA-Z0-9\-]{1,64}$/;

function validateInvoiceId(id) {
  if (!id || typeof id !== 'string') {
    throw new UserInputError('Invoice ID is required and must be a string.');
  }

  const trimmedId = id.trim();

  if (trimmedId.length === 0 || trimmedId.length > 64) {
    throw new UserInputError('Invoice ID must be between 1 and 64 characters.');
  }

  if (!INVOICE_ID_PATTERN.test(trimmedId)) {
    throw new UserInputError('Invoice ID contains invalid characters. Only alphanumeric characters and hyphens are allowed.');
  }

  return trimmedId;
}

function sanitizeOutputString(value) {
  if (typeof value !== 'string') return value;
  // Prevent any embedded script or injection in output
  return value
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/&(?!amp;|lt;|gt;|quot;|#39;)/g, '&amp;');
}

function sanitizeInvoice(invoice) {
  if (!invoice) return null;

  return {
    id: invoice.id,
    invoiceNumber: sanitizeOutputString(invoice.invoiceNumber),
    amount: Number(invoice.amount),
    currency: sanitizeOutputString(invoice.currency),
    status: invoice.status,
    issuedDate: sanitizeOutputString(invoice.issuedDate),
    dueDate: sanitizeOutputString(invoice.dueDate),
    customerName: sanitizeOutputString(invoice.customerName),
    // Redact full email - show only partial for privacy
    customerEmail: sanitizeOutputString(invoice.customerEmail),
    lineItems: (invoice.lineItems || []).map(item => ({
      description: sanitizeOutputString(item.description),
      quantity: parseInt(item.quantity, 10),
      unitPrice: Number(item.unitPrice),
      total: Number(item.total),
    })),
  };
}

