class InvoiceRepository {
  constructor(db) {
    this.db = db;
  }

  async findByIdForUser(invoiceId, userId) {
    // Parameterized query prevents SQL injection
    // The query enforces that the user can only access their own invoices
    const query = 'SELECT * FROM invoices WHERE id = $1 AND user_id = $2 LIMIT 1';
    const params = [invoiceId, userId];

    try {
      const result = await this.db.query(query, params);
      return result.rows.length > 0 ? result.rows[0] : null;
    } catch (error) {
      // Log error securely without exposing sensitive details
      console.error('Database query failed for invoice lookup', {
        userId: userId,
        // Do NOT log the full invoiceId to prevent log injection attacks
        invoiceIdLength: invoiceId.length,
        errorCode: error.code,
      });
      throw new ApolloError('An error occurred while retrieving the invoice.', 'INTERNAL_ERROR');
    }
  }

  async findLineItemsByInvoiceId(invoiceId, userId) {
    const query = 'SELECT * FROM line_items WHERE invoice_id = $1 AND invoice_id IN (SELECT id FROM invoices WHERE user_id = $2)';
    const params = [invoiceId, userId];

    try {
      const result = await this.db.query(query, params);
      return result.rows;
    } catch (error) {
      console.error('Database query failed for line items lookup', {
        userId: userId,
        errorCode: error.code,
      });
      throw new ApolloError('An error occurred while retrieving line items.', 'INTERNAL_ERROR');
    }
  }
}

// Resolvers with authorization checks
const resolvers = {
  Query: {
    invoice: async (_parent, args, context) => {
      // Verify authenticated user exists in context
      // Authentication middleware has already verified the token,
      // but we must ensure the user object is present
      if (!context.user || !context.user.id) {
        throw new ForbiddenError('Authentication required. No valid user context found.');
      }

      const userId = context.user.id;

      // Validate and sanitize input
      const invoiceId = validateInvoiceId(args.id);

      // Fetch invoice with authorization scoped to the authenticated user
      const invoiceRepo = context.dataSources.invoiceRepository;
      const invoice = await invoiceRepo.findByIdForUser(invoiceId, userId);

      if (!invoice) {
        // Return null rather than distinguishing between "not found" and "not authorized"
        // This prevents enumeration attacks
        return null;
      }

      // Fetch associated line items (also scoped to user)
      const lineItems = await invoiceRepo.findLineItemsByInvoiceId(invoiceId, userId);
      invoice.lineItems = lineItems;

      // Sanitize output before returning
      return sanitizeInvoice(invoice);
    },
  },
};

// Server setup with security hardening
async function createServer(db) {
  const app = express();

  // Security headers
  app.use(helmet({
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc: ["'self'"],
        styleSrc: ["'self'"],
      },
    },
    hsts: {
      maxAge: 31536000,
      includeSubDomains: true,
    },
  }));

  // Rate limiting to prevent abuse
  const apiLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 100, // limit each IP to 100 requests per windowMs
    standardHeaders: true,
    legacyHeaders: false,
    message: { errors: [{ message: 'Too many requests, please try again later.' }] },
  });

  app.use('/graphql', apiLimiter);

  // Disable introspection in production
  const isProduction = process.env.NODE_ENV === 'production';

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    introspection: !isProduction,
    // Disable GraphQL Playground in production
    playground: !isProduction,
    // Query depth limiting to prevent deeply nested malicious queries
    validationRules: [
      depthLimit(5),
      createComplexityLimitRule(1000, {
        onCost: (cost) => {
          if (cost > 800) {
            console.warn(`GraphQL query approaching complexity limit: ${cost}`);
          }
        },
      }),
    ],
    context: ({ req }) => {
      // The user is already authenticated by middleware
      // We extract the user from the request
      const user = req.user;

      return {
        user,
        dataSources: {
          invoiceRepository: new InvoiceRepository(db),
        },
      };
    },
    // Custom error formatting - never expose internal details
    formatError: (error) => {
      // Log the full error internally
      console.error('GraphQL Error:', {
        message: error.message,
        code: error.extensions?.code,
        // Do not log stack traces to external-facing logs in production
        ...(isProduction ? {} : { stack: error.extensions?.exception?.stacktrace }),
      });

      // Return sanitized error to client
      const safeError = {
        message: error.message,
        extensions: {
          code: error.extensions?.code || 'INTERNAL_SERVER_ERROR',
        },
      };

      // In production, mask unexpected errors
      if (isProduction && !['BAD_USER_INPUT', 'UNAUTHENTICATED', 'FORBIDDEN'].includes(error.extensions?.code)) {
        safeError.message = 'An unexpected error occurred.';
        safeError.extensions.code = 'INTERNAL_SERVER_ERROR';
      }

      return safeError;
    },
    // Limit request size to prevent DoS
    persistedQueries: false,
  });

  await server.start();

  server.applyMiddleware({
    app,
    path: '/graphql',
    cors: {
      origin: process.env.ALLOWED_ORIGINS ? process.env.ALLOWED_ORIGINS.split(',') : false,
      credentials: true,
      methods: ['POST'],
      allowedHeaders: ['Content-Type', 'Authorization'],
    },
    bodyParserConfig: {
      limit: '10kb', // Limit request body size
    },
  });

  return { app, server };
}

// Express body size limit middleware
function bodySizeLimit(req, res, next) {
  const MAX_BODY_SIZE = 10 * 1024; // 10KB
  let size = 0;

  req.on('data', (chunk) => {
    size += chunk.length;
    if (size > MAX_BODY_SIZE) {
      res.status(413).json({ errors: [{ message: 'Request body too large.' }] });
      req.destroy();
    }
  });

  next();
}

